using ContosoUniversity.Models;
using System;
using System.Collections.Generic;
using System.ComponentModel.DataAnnotations;
using System.Linq;
using Xunit;

namespace ContosoUniversity.Tests.Models
{
    public class ModelValidationTests
    {
        private static IList<ValidationResult> ValidateModel(object model)
        {
            var results = new List<ValidationResult>();
            var context = new ValidationContext(model, null, null);
            Validator.TryValidateObject(model, context, results, true);
            return results;
        }

        #region Student Tests

        [Fact]
        public void Student_ValidModel_NoValidationErrors()
        {
            var student = new Student
            {
                LastName = "Smith",
                FirstMidName = "John",
                EnrollmentDate = new DateTime(2020, 9, 1)
            };

            var results = ValidateModel(student);
            Assert.Empty(results);
        }

        [Fact]
        public void Student_MissingLastName_HasValidationError()
        {
            var student = new Student
            {
                FirstMidName = "John",
                EnrollmentDate = new DateTime(2020, 9, 1)
            };

            var results = ValidateModel(student);
            Assert.Contains(results, r => r.MemberNames.Any(m => m == "LastName"));
        }

        [Fact]
        public void Student_MissingFirstMidName_HasValidationError()
        {
            var student = new Student
            {
                LastName = "Smith",
                EnrollmentDate = new DateTime(2020, 9, 1)
            };

            var results = ValidateModel(student);
            Assert.Contains(results, r => r.MemberNames.Any(m => m == "FirstMidName"));
        }

        [Fact]
        public void Student_LastNameTooLong_HasValidationError()
        {
            var student = new Student
            {
                LastName = new string('A', 51),
                FirstMidName = "John",
                EnrollmentDate = new DateTime(2020, 9, 1)
            };

            var results = ValidateModel(student);
            Assert.Contains(results, r => r.MemberNames.Any(m => m == "LastName"));
        }

        [Fact]
        public void Student_FirstMidNameTooLong_HasValidationError()
        {
            var student = new Student
            {
                LastName = "Smith",
                FirstMidName = new string('B', 51),
                EnrollmentDate = new DateTime(2020, 9, 1)
            };

            var results = ValidateModel(student);
            Assert.Contains(results, r => r.MemberNames.Any(m => m == "FirstMidName"));
        }

        [Fact]
        public void Student_FullName_ReturnsLastCommaFirst()
        {
            var student = new Student
            {
                LastName = "Smith",
                FirstMidName = "John"
            };

            Assert.Equal("Smith, John", student.FullName);
        }

        [Fact]
        public void Student_LastNameMaxLength_IsValid()
        {
            var student = new Student
            {
                LastName = new string('A', 50),
                FirstMidName = "John",
                EnrollmentDate = new DateTime(2020, 9, 1)
            };

            var results = ValidateModel(student);
            Assert.DoesNotContain(results, r => r.MemberNames.Any(m => m == "LastName"));
        }

        #endregion

        #region Instructor Tests

        [Fact]
        public void Instructor_ValidModel_NoValidationErrors()
        {
            var instructor = new Instructor
            {
                LastName = "Doe",
                FirstMidName = "Jane",
                HireDate = new DateTime(2010, 8, 15)
            };

            var results = ValidateModel(instructor);
            Assert.Empty(results);
        }

        [Fact]
        public void Instructor_MissingLastName_HasValidationError()
        {
            var instructor = new Instructor
            {
                FirstMidName = "Jane",
                HireDate = new DateTime(2010, 8, 15)
            };

            var results = ValidateModel(instructor);
            Assert.Contains(results, r => r.MemberNames.Any(m => m == "LastName"));
        }

        [Fact]
        public void Instructor_MissingFirstName_HasValidationError()
        {
            var instructor = new Instructor
            {
                LastName = "Doe",
                HireDate = new DateTime(2010, 8, 15)
            };

            var results = ValidateModel(instructor);
            Assert.Contains(results, r => r.MemberNames.Any(m => m == "FirstMidName"));
        }

        [Fact]
        public void Instructor_FullName_ReturnsLastCommaFirst()
        {
            var instructor = new Instructor
            {
                LastName = "Doe",
                FirstMidName = "Jane"
            };

            Assert.Equal("Doe, Jane", instructor.FullName);
        }

        #endregion

        #region Course Tests

        [Fact]
        public void Course_ValidModel_NoValidationErrors()
        {
            var course = new Course
            {
                CourseID = 1050,
                Title = "Chemistry",
                Credits = 3,
                DepartmentID = 1
            };

            var results = ValidateModel(course);
            Assert.Empty(results);
        }

        [Fact]
        public void Course_TitleTooShort_HasValidationError()
        {
            var course = new Course
            {
                CourseID = 1050,
                Title = "AB",
                Credits = 3,
                DepartmentID = 1
            };

            var results = ValidateModel(course);
            Assert.Contains(results, r => r.MemberNames.Any(m => m == "Title"));
        }

        [Fact]
        public void Course_TitleTooLong_HasValidationError()
        {
            var course = new Course
            {
                CourseID = 1050,
                Title = new string('X', 51),
                Credits = 3,
                DepartmentID = 1
            };

            var results = ValidateModel(course);
            Assert.Contains(results, r => r.MemberNames.Any(m => m == "Title"));
        }

        [Fact]
        public void Course_CreditsAboveRange_HasValidationError()
        {
            var course = new Course
            {
                CourseID = 1050,
                Title = "Chemistry",
                Credits = 6,
                DepartmentID = 1
            };

            var results = ValidateModel(course);
            Assert.Contains(results, r => r.MemberNames.Any(m => m == "Credits"));
        }

        [Fact]
        public void Course_NegativeCredits_HasValidationError()
        {
            var course = new Course
            {
                CourseID = 1050,
                Title = "Chemistry",
                Credits = -1,
                DepartmentID = 1
            };

            var results = ValidateModel(course);
            Assert.Contains(results, r => r.MemberNames.Any(m => m == "Credits"));
        }

        [Fact]
        public void Course_ZeroCredits_IsValid()
        {
            var course = new Course
            {
                CourseID = 1050,
                Title = "Chemistry",
                Credits = 0,
                DepartmentID = 1
            };

            var results = ValidateModel(course);
            Assert.DoesNotContain(results, r => r.MemberNames.Any(m => m == "Credits"));
        }

        [Fact]
        public void Course_FiveCredits_IsValid()
        {
            var course = new Course
            {
                CourseID = 1050,
                Title = "Chemistry",
                Credits = 5,
                DepartmentID = 1
            };

            var results = ValidateModel(course);
            Assert.DoesNotContain(results, r => r.MemberNames.Any(m => m == "Credits"));
        }

        #endregion

        #region Department Tests

        [Fact]
        public void Department_ValidModel_NoValidationErrors()
        {
            var department = new Department
            {
                Name = "English",
                Budget = 100000,
                StartDate = new DateTime(2007, 9, 1)
            };

            var results = ValidateModel(department);
