using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.EntityFrameworkCore;
using System;
using System.Collections.Generic;
using System.Linq;
using Xunit;

namespace ContosoUniversity.Tests
{
    public class SchoolContextTests
    {
        [Fact]
        public void SchoolContext_CanAddAndRetrieveStudent()
        {
            using var context = TestHelpers.CreateInMemoryContext();
            var student = new Student
            {
                LastName = "Test",
                FirstMidName = "Student",
                EnrollmentDate = new DateTime(2020, 9, 1)
            };

            context.Students.Add(student);
            context.SaveChanges();

            var retrieved = context.Students.First();
            Assert.Equal("Test", retrieved.LastName);
            Assert.Equal("Student", retrieved.FirstMidName);
        }

        [Fact]
        public void SchoolContext_CanAddAndRetrieveCourse()
        {
            using var context = TestHelpers.CreateInMemoryContext();
            context.Departments.Add(new Department { DepartmentID = 1, Name = "Test Dept", Budget = 100, StartDate = DateTime.Now });
            context.SaveChanges();

            var course = new Course { CourseID = 1050, Title = "Chemistry", Credits = 3, DepartmentID = 1 };
            context.Courses.Add(course);
            context.SaveChanges();

            var retrieved = context.Courses.First();
            Assert.Equal("Chemistry", retrieved.Title);
            Assert.Equal(3, retrieved.Credits);
        }

        [Fact]
        public void SchoolContext_CanAddAndRetrieveInstructor()
        {
            using var context = TestHelpers.CreateInMemoryContext();
            var instructor = new Instructor
            {
                LastName = "Test",
                FirstMidName = "Instructor",
                HireDate = new DateTime(2010, 1, 1)
            };

            context.Instructors.Add(instructor);
            context.SaveChanges();

            var retrieved = context.Instructors.First();
            Assert.Equal("Test", retrieved.LastName);
        }

        [Fact]
        public void SchoolContext_CanAddEnrollment()
        {
            using var context = TestHelpers.CreateInMemoryContext();
            var student = new Student { LastName = "Test", FirstMidName = "Student", EnrollmentDate = DateTime.Now };
            context.Students.Add(student);
            context.Departments.Add(new Department { DepartmentID = 1, Name = "Test", Budget = 100, StartDate = DateTime.Now });
            context.SaveChanges();
            context.Courses.Add(new Course { CourseID = 100, Title = "Test Course", Credits = 3, DepartmentID = 1 });
            context.SaveChanges();

            var enrollment = new Enrollment { StudentID = student.ID, CourseID = 100, Grade = Grade.B };
            context.Enrollments.Add(enrollment);
            context.SaveChanges();

            var retrieved = context.Enrollments.First();
            Assert.Equal(Grade.B, retrieved.Grade);
        }

        [Fact]
        public void SchoolContext_CanAddDepartment()
        {
            using var context = TestHelpers.CreateInMemoryContext();
            var department = new Department
            {
                Name = "Engineering",
                Budget = 500000,
                StartDate = new DateTime(2007, 9, 1)
            };

            context.Departments.Add(department);
            context.SaveChanges();

            var retrieved = context.Departments.First();
            Assert.Equal("Engineering", retrieved.Name);
            Assert.Equal(500000, retrieved.Budget);
        }

        [Fact]
        public void SchoolContext_CourseAssignment_CompositeKey()
        {
            using var context = TestHelpers.CreateInMemoryContext();
            var instructor = new Instructor
            {
                ID = 1,
                LastName = "Test",
                FirstMidName = "Instructor",
                HireDate = DateTime.Now,
                CourseAssignments = new List<CourseAssignment>()
            };
            context.Instructors.Add(instructor);
            context.Departments.Add(new Department { DepartmentID = 1, Name = "Test", Budget = 100, StartDate = DateTime.Now });
            context.SaveChanges();
            context.Courses.Add(new Course { CourseID = 100, Title = "Test", Credits = 3, DepartmentID = 1 });
            context.SaveChanges();

            context.CourseAssignments.Add(new CourseAssignment { InstructorID = 1, CourseID = 100 });
            context.SaveChanges();

            var ca = context.CourseAssignments.First();
            Assert.Equal(1, ca.InstructorID);
            Assert.Equal(100, ca.CourseID);
        }

        [Fact]
        public void SchoolContext_OfficeAssignment_OneToOne()
        {
            using var context = TestHelpers.CreateInMemoryContext();
            var instructor = new Instructor
            {
                ID = 1,
                LastName = "Test",
                FirstMidName = "Instructor",
                HireDate = DateTime.Now,
                CourseAssignments = new List<CourseAssignment>(),
                OfficeAssignment = new OfficeAssignment { Location = "Room 123" }
            };

            context.Instructors.Add(instructor);
            context.SaveChanges();

            var saved = context.Instructors.Include(i => i.OfficeAssignment).First();
            Assert.NotNull(saved.OfficeAssignment);
            Assert.Equal("Room 123", saved.OfficeAssignment.Location);
        }

        [Fact]
        public void SchoolContext_Notification_CanBeStored()
        {
            using var context = TestHelpers.CreateInMemoryContext();
            var notification = new Notification
            {
                EntityType = "Student",
                EntityId = "1",
                Operation = "CREATE",
                Message = "Test notification",
                CreatedAt = DateTime.Now,
                CreatedBy = "Admin",
                IsRead = false
            };

            context.Notifications.Add(notification);
            context.SaveChanges();

            var retrieved = context.Notifications.First();
            Assert.Equal("Student", retrieved.EntityType);
            Assert.Equal("Test notification", retrieved.Message);
        }

        [Fact]
        public void SchoolContext_Student_HasEnrollmentsCollection()
        {
            using var context = TestHelpers.CreateInMemoryContext();
            var student = new Student
            {
                LastName = "Test",
                FirstMidName = "Student",
                EnrollmentDate = DateTime.Now,
                Enrollments = new List<Enrollment>()
            };

            context.Students.Add(student);
            context.Departments.Add(new Department { DepartmentID = 1, Name = "Test", Budget = 100, StartDate = DateTime.Now });
            context.SaveChanges();
            context.Courses.Add(new Course { CourseID = 100, Title = "Test", Credits = 3, DepartmentID = 1 });
            context.Courses.Add(new Course { CourseID = 200, Title = "Test2", Credits = 4, DepartmentID = 1 });
            context.SaveChanges();

            context.Enrollments.Add(new Enrollment { StudentID = student.ID, CourseID = 100, Grade = Grade.A });
            context.Enrollments.Add(new Enrollment { StudentID = student.ID, CourseID = 200, Grade = Grade.B });
            context.SaveChanges();

            var loaded = context.Students.Include(s => s.Enrollments).First();
            Assert.Equal(2, loaded.Enrollments.Count);
        }
    }
}

