            };

            var results = ValidateModel(notification);
            Assert.Contains(results, r => r.MemberNames.Any(m => m == "Message"));
        }

        [Fact]
        public void Notification_MissingOperation_HasValidationError()
        {
            var notification = new Notification
            {
                EntityType = "Student",
                EntityId = "1",
                Message = "Test message",
                CreatedAt = DateTime.Now
            };

            var results = ValidateModel(notification);
            Assert.Contains(results, r => r.MemberNames.Any(m => m == "Operation"));
        }

        [Fact]
        public void Notification_MissingEntityId_HasValidationError()
        {
            var notification = new Notification
            {
                EntityType = "Student",
                Operation = "CREATE",
                Message = "Test message",
                CreatedAt = DateTime.Now
            };

            var results = ValidateModel(notification);
            Assert.Contains(results, r => r.MemberNames.Any(m => m == "EntityId"));
        }

        #endregion

        #region ErrorViewModel Tests

        [Fact]
        public void ErrorViewModel_WithRequestId_ShowRequestIdReturnsTrue()
        {
            var model = new ErrorViewModel { RequestId = "abc123" };
            Assert.True(model.ShowRequestId);
        }

        [Fact]
        public void ErrorViewModel_WithNullRequestId_ShowRequestIdReturnsFalse()
        {
            var model = new ErrorViewModel { RequestId = null };
            Assert.False(model.ShowRequestId);
        }

        [Fact]
        public void ErrorViewModel_WithEmptyRequestId_ShowRequestIdReturnsFalse()
        {
            var model = new ErrorViewModel { RequestId = "" };
            Assert.False(model.ShowRequestId);
        }

