        #region OfficeAssignment Tests

        [Fact]
        public void OfficeAssignment_LocationTooLong_HasValidationError()
        {
            var assignment = new OfficeAssignment
            {
                InstructorID = 1,
                Location = new string('X', 51)
            };

            var results = ValidateModel(assignment);
            Assert.Contains(results, r => r.MemberNames.Any(m => m == "Location"));
        }

