using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using Microsoft.AspNetCore.Mvc.ViewFeatures;
using Microsoft.EntityFrameworkCore;
using System;
using System.Collections.Generic;
using System.Linq;
using Xunit;

namespace ContosoUniversity.Tests.Controllers
{
    public class DepartmentsControllerTests : IDisposable
    {
        private readonly SchoolContext _context;
        private readonly DepartmentsController _controller;

        public DepartmentsControllerTests()
        {
            _context = TestHelpers.CreateInMemoryContext();
            _controller = new DepartmentsController(_context);
            _controller.TempData = new TempDataDictionary(new DefaultHttpContext(), new SessionStateTempDataProvider(new SessionStateTempDataSerializer()));
        }

        public void Dispose()
        {
            _controller.Dispose();
            _context.Dispose();
        }

        #region Index Tests

        [Fact]
        public void Index_ReturnsViewWithDepartments()
        {
            TestHelpers.SeedDepartments(_context);

            var result = _controller.Index() as ViewResult;

            Assert.NotNull(result);
            var model = result.Model as List<Department>;
            Assert.NotNull(model);
            Assert.Equal(3, model.Count);
        }

        [Fact]
        public void Index_EmptyDatabase_ReturnsEmptyList()
        {
            var result = _controller.Index() as ViewResult;

            Assert.NotNull(result);
            var model = result.Model as List<Department>;
            Assert.NotNull(model);
            Assert.Empty(model);
        }

        #endregion

        #region Details Tests

        [Fact]
        public void Details_NullId_ReturnsBadRequest()
        {
            var result = _controller.Details(null);

            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Details_InvalidId_ReturnsNotFound()
        {
            var result = _controller.Details(999);

            Assert.IsType<NotFoundResult>(result);
        }

        [Fact]
        public void Details_ValidId_ReturnsViewWithDepartment()
        {
            TestHelpers.SeedDepartments(_context);

            var result = _controller.Details(1) as ViewResult;

            Assert.NotNull(result);
            var department = result.Model as Department;
            Assert.NotNull(department);
            Assert.Equal("English", department.Name);
        }

        #endregion

        #region Create GET Tests

        [Fact]
        public void Create_Get_ReturnsView()
        {
            TestHelpers.SeedInstructors(_context);

            var result = _controller.Create() as ViewResult;

            Assert.NotNull(result);
        }

        #endregion

        #region Create POST Tests

        [Fact]
        public void Create_ValidDepartment_RedirectsToIndex()
        {
            TestHelpers.SeedInstructors(_context);
            var department = new Department
            {
                Name = "Science",
                Budget = 200000,
                StartDate = new DateTime(2020, 1, 1),
                InstructorID = 10
            };

            var result = _controller.Create(department);

            var redirect = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirect.ActionName);
        }

        [Fact]
        public void Create_ValidDepartment_SavesInDatabase()
        {
            var department = new Department
            {
                Name = "Science",
                Budget = 200000,
                StartDate = new DateTime(2020, 1, 1)
            };

            _controller.Create(department);

            Assert.Single(_context.Departments);
            Assert.Equal("Science", _context.Departments.First().Name);
        }

        [Fact]
        public void Create_InvalidModelState_ReturnsView()
        {
            _controller.ModelState.AddModelError("Name", "Required");
            var department = new Department
            {
                Budget = 200000,
                StartDate = new DateTime(2020, 1, 1)
            };

            var result = _controller.Create(department) as ViewResult;

            Assert.NotNull(result);
        }

        #endregion

        #region Edit GET Tests

        [Fact]
        public void Edit_NullId_ReturnsBadRequest()
        {
            var result = _controller.Edit((int?)null);

            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Edit_InvalidId_ReturnsNotFound()
        {
            var result = _controller.Edit(999);

            Assert.IsType<NotFoundResult>(result);
        }

        [Fact]
        public void Edit_ValidId_ReturnsViewWithDepartment()
        {
            TestHelpers.SeedDepartments(_context);
            TestHelpers.SeedInstructors(_context);

            var result = _controller.Edit(1) as ViewResult;

            Assert.NotNull(result);
            var department = result.Model as Department;
            Assert.NotNull(department);
            Assert.Equal("English", department.Name);
        }

        #endregion

        #region Edit POST Tests

        [Fact]
        public void Edit_ValidDepartment_RedirectsToIndex()
        {
            TestHelpers.SeedDepartments(_context);
            TestHelpers.SeedInstructors(_context);
            var tracked = _context.Departments.Find(1)!;
            _context.Entry(tracked).State = EntityState.Detached;

            var department = new Department
            {
                DepartmentID = 1,
                Name = "Updated English",
                Budget = 400000,
                StartDate = new DateTime(2007, 9, 1),
                RowVersion = new byte[] { 0, 0, 0, 1 }
            };

            var result = _controller.Edit(department);

            var redirect = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirect.ActionName);
        }

        [Fact]
        public void Edit_InvalidModelState_ReturnsView()
        {
            TestHelpers.SeedDepartments(_context);
            TestHelpers.SeedInstructors(_context);
            _controller.ModelState.AddModelError("Name", "Required");
            var department = new Department
            {
                DepartmentID = 1,
                Budget = 400000,
                StartDate = new DateTime(2007, 9, 1)
            };

            var result = _controller.Edit(department) as ViewResult;

            Assert.NotNull(result);
        }

        #endregion

        #region Delete GET Tests

        [Fact]
        public void Delete_NullId_ReturnsBadRequest()
        {
            var result = _controller.Delete(null);

            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Delete_InvalidId_ReturnsNotFound()
        {
            var result = _controller.Delete(999);

            Assert.IsType<NotFoundResult>(result);
        }

        [Fact]
        public void Delete_ValidId_ReturnsViewWithDepartment()
        {
            TestHelpers.SeedDepartments(_context);

            var result = _controller.Delete(1) as ViewResult;

            Assert.NotNull(result);
            var department = result.Model as Department;
            Assert.NotNull(department);
            Assert.Equal("English", department.Name);
        }

        #endregion

        #region DeleteConfirmed Tests

        [Fact]
        public void DeleteConfirmed_ValidId_RemovesDepartmentAndRedirects()
        {
            TestHelpers.SeedDepartments(_context);
            var countBefore = _context.Departments.Count();

            var result = _controller.DeleteConfirmed(1);

            var redirect = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirect.ActionName);
            Assert.Equal(countBefore - 1, _context.Departments.Count());
        }

        #endregion
    }
}

