using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Models.SchoolViewModels;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using Microsoft.AspNetCore.Mvc.ViewFeatures;
using Microsoft.EntityFrameworkCore;
using System;
using System.Collections.Generic;
using System.Linq;
using Xunit;

namespace ContosoUniversity.Tests.Controllers
{
    public class InstructorsControllerTests : IDisposable
    {
        private readonly SchoolContext _context;
        private readonly InstructorsController _controller;

        public InstructorsControllerTests()
        {
            _context = TestHelpers.CreateInMemoryContext();
            _controller = new InstructorsController(_context);
            _controller.TempData = new TempDataDictionary(new DefaultHttpContext(), new SessionStateTempDataProvider(new SessionStateTempDataSerializer()));
        }

        public void Dispose()
        {
            _controller.Dispose();
            _context.Dispose();
        }

        private void SeedInstructorsWithCourses()
        {
            TestHelpers.SeedDepartments(_context);

            var courses = new List<Course>
            {
                new Course { CourseID = 1050, Title = "Chemistry", Credits = 3, DepartmentID = 1, Enrollments = new List<Enrollment>() },
                new Course { CourseID = 4022, Title = "Microeconomics", Credits = 3, DepartmentID = 2, Enrollments = new List<Enrollment>() }
            };
            _context.Courses.AddRange(courses);
            _context.SaveChanges();

            var instructors = new List<Instructor>
            {
                new Instructor
                {
                    ID = 10,
                    LastName = "Abercrombie",
                    FirstMidName = "Kim",
                    HireDate = new DateTime(1995, 3, 11),
                    CourseAssignments = new List<CourseAssignment>
                    {
                        new CourseAssignment { CourseID = 1050, InstructorID = 10 }
                    },
                    OfficeAssignment = new OfficeAssignment { Location = "Room 101", InstructorID = 10 }
                },
                new Instructor
                {
                    ID = 11,
                    LastName = "Fakhouri",
                    FirstMidName = "Fadi",
                    HireDate = new DateTime(2002, 7, 6),
                    CourseAssignments = new List<CourseAssignment>
                    {
                        new CourseAssignment { CourseID = 4022, InstructorID = 11 }
                    }
                }
            };
            _context.Instructors.AddRange(instructors);
            _context.SaveChanges();
        }

        #region Index Tests

        [Fact]
        public void Index_ReturnsViewWithInstructorIndexData()
        {
            SeedInstructorsWithCourses();

            var result = _controller.Index(null, null) as ViewResult;

            Assert.NotNull(result);
            var model = result.Model as InstructorIndexData;
            Assert.NotNull(model);
            Assert.Equal(2, model.Instructors.Count());
        }

        [Fact]
        public void Index_WithInstructorId_IncludesCourses()
        {
            SeedInstructorsWithCourses();

            var result = _controller.Index(10, null) as ViewResult;

            Assert.NotNull(result);
            var model = result.Model as InstructorIndexData;
            Assert.NotNull(model);
            Assert.NotNull(model.Courses);
            Assert.Single(model.Courses);
            Assert.Equal("Chemistry", model.Courses.First().Title);
        }

        [Fact]
        public void Index_WithCourseId_IncludesEnrollments()
        {
            SeedInstructorsWithCourses();
            // Add enrollment to the course
            _context.Students.Add(new Student { ID = 1, LastName = "Smith", FirstMidName = "John", EnrollmentDate = DateTime.Now });
            _context.SaveChanges();
            _context.Enrollments.Add(new Enrollment { CourseID = 1050, StudentID = 1, Grade = Grade.A });
            _context.SaveChanges();

            var result = _controller.Index(10, 1050) as ViewResult;

            Assert.NotNull(result);
            var model = result.Model as InstructorIndexData;
            Assert.NotNull(model);
            Assert.NotNull(model.Enrollments);
            Assert.Single(model.Enrollments);
        }

        [Fact]
        public void Index_NoInstructors_ReturnsEmptyModel()
        {
            var result = _controller.Index(null, null) as ViewResult;

            Assert.NotNull(result);
            var model = result.Model as InstructorIndexData;
            Assert.NotNull(model);
            Assert.Empty(model.Instructors);
        }

        #endregion

        #region Details Tests

        [Fact]
        public void Details_NullId_ReturnsBadRequest()
        {
            var result = _controller.Details(null);

            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Details_InvalidId_ReturnsNotFound()
        {
            var result = _controller.Details(999);

            Assert.IsType<NotFoundResult>(result);
        }

        [Fact]
        public void Details_ValidId_ReturnsViewWithInstructor()
        {
            SeedInstructorsWithCourses();

            var result = _controller.Details(10) as ViewResult;

            Assert.NotNull(result);
            var instructor = result.Model as Instructor;
            Assert.NotNull(instructor);
            Assert.Equal("Abercrombie", instructor.LastName);
        }

        #endregion

        #region Create GET Tests

        [Fact]
        public void Create_Get_ReturnsViewWithInstructor()
        {
            SeedInstructorsWithCourses();

            var result = _controller.Create() as ViewResult;

            Assert.NotNull(result);
            var model = result.Model as Instructor;
            Assert.NotNull(model);
            Assert.NotNull(model.CourseAssignments);
            Assert.Empty(model.CourseAssignments);
        }

        #endregion

        #region Create POST Tests

        [Fact]
        public void Create_ValidInstructor_RedirectsToIndex()
        {
            SeedInstructorsWithCourses();
            var instructor = new Instructor
            {
                LastName = "NewInstructor",
                FirstMidName = "New",
                HireDate = new DateTime(2020, 1, 1),
                CourseAssignments = new List<CourseAssignment>()
            };

            var result = _controller.Create(instructor, null!);

            var redirect = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirect.ActionName);
        }

        [Fact]
        public void Create_WithSelectedCourses_AssignsCourses()
        {
            SeedInstructorsWithCourses();
            var instructor = new Instructor
            {
                LastName = "NewInstructor",
                FirstMidName = "New",
                HireDate = new DateTime(2020, 1, 1),
                CourseAssignments = new List<CourseAssignment>()
            };

            _controller.Create(instructor, new[] { "1050", "4022" });

            var saved = _context.Instructors.Include(i => i.CourseAssignments)
                .First(i => i.LastName == "NewInstructor");
            Assert.Equal(2, saved.CourseAssignments.Count);
        }

        [Fact]
        public void Create_InvalidModelState_ReturnsView()
        {
            SeedInstructorsWithCourses();
            _controller.ModelState.AddModelError("LastName", "Required");
            var instructor = new Instructor
            {
                FirstMidName = "New",
                HireDate = new DateTime(2020, 1, 1),
                CourseAssignments = new List<CourseAssignment>()
            };

            var result = _controller.Create(instructor, null!) as ViewResult;

            Assert.NotNull(result);
        }

        #endregion

        #region Edit GET Tests

        [Fact]
        public void Edit_NullId_ReturnsBadRequest()
        {
            var result = _controller.Edit((int?)null);

            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Edit_ValidId_ReturnsViewWithInstructor()
        {
            SeedInstructorsWithCourses();

            var result = _controller.Edit(10) as ViewResult;

            Assert.NotNull(result);
            var instructor = result.Model as Instructor;
            Assert.NotNull(instructor);
            Assert.Equal("Abercrombie", instructor.LastName);
        }

        #endregion

        #region Delete GET Tests

        [Fact]
        public void Delete_NullId_ReturnsBadRequest()
        {
            var result = _controller.Delete(null);

            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Delete_InvalidId_ReturnsNotFound()
        {
            var result = _controller.Delete(999);

            Assert.IsType<NotFoundResult>(result);
        }

        [Fact]
        public void Delete_ValidId_ReturnsViewWithInstructor()
        {
            SeedInstructorsWithCourses();

            var result = _controller.Delete(10) as ViewResult;

            Assert.NotNull(result);
            var instructor = result.Model as Instructor;
            Assert.NotNull(instructor);
            Assert.Equal("Abercrombie", instructor.LastName);
        }

        #endregion

        #region DeleteConfirmed Tests

        [Fact]
        public void DeleteConfirmed_ValidId_RemovesInstructorAndRedirects()
        {
            SeedInstructorsWithCourses();
            var countBefore = _context.Instructors.Count();

            var result = _controller.DeleteConfirmed(10);

            var redirect = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirect.ActionName);
            Assert.Equal(countBefore - 1, _context.Instructors.Count());
        }

        [Fact]
        public void DeleteConfirmed_InstructorAsDepartmentAdmin_ClearsDepartmentAdministrator()
        {
            SeedInstructorsWithCourses();
            var department = _context.Departments.First();
            department.InstructorID = 10;
            _context.SaveChanges();

            _controller.DeleteConfirmed(10);

            var updatedDept = _context.Departments.Find(department.DepartmentID)!;
            Assert.Null(updatedDept.InstructorID);
        }

        #endregion
    }
}

