using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Services;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using Microsoft.AspNetCore.Mvc.ViewFeatures;
using System;
using Xunit;

namespace ContosoUniversity.Tests.Controllers
{
    public class NotificationsControllerTests : IDisposable
    {
        private readonly SchoolContext _context;
        private readonly NotificationsController _controller;
        private readonly NotificationService _notificationService;

        public NotificationsControllerTests()
        {
            _context = TestHelpers.CreateInMemoryContext();
            _controller = new NotificationsController(_context);
            _controller.TempData = new TempDataDictionary(new DefaultHttpContext(), new SessionStateTempDataProvider(new SessionStateTempDataSerializer()));
            _notificationService = new NotificationService();
            // Drain existing notifications
            while (_notificationService.ReceiveNotification() != null) { }
        }

        public void Dispose()
        {
            _controller.Dispose();
            _context.Dispose();
            _notificationService.Dispose();
        }

        [Fact]
        public void GetNotifications_EmptyQueue_ReturnsSuccessWithEmptyList()
        {
            // Drain any notifications first
            while (true)
            {
                var json = _controller.GetNotifications();
                var result = json.Value as dynamic;
                // Just verify it returns successfully - queue state is shared
                Assert.NotNull(json);
                break;
            }
        }

        [Fact]
        public void GetNotifications_WithNotifications_ReturnsNotifications()
        {
            _notificationService.SendNotification("Student", "1", "Test Student", EntityOperation.CREATE);

            var result = _controller.GetNotifications();

            Assert.NotNull(result);
            Assert.IsType<JsonResult>(result);
        }

        [Fact]
        public void MarkAsRead_ReturnsSuccess()
        {
            var result = _controller.MarkAsRead(1);

            Assert.NotNull(result);
            Assert.IsType<JsonResult>(result);
        }

        [Fact]
        public void Index_ReturnsView()
        {
            var result = _controller.Index() as ViewResult;
            Assert.NotNull(result);
        }
    }
}

