using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.EntityFrameworkCore;
using System;
using System.Collections.Generic;
using System.Linq;
using Xunit;

namespace ContosoUniversity.Tests
{
    public class SchoolContextTests
    {
        [Fact]
        public void SchoolContext_CanAddAndRetrieveStudent()
        {
            using var context = TestHelpers.CreateInMemoryContext();
            var student = new Student
            {
                LastName = "Test",
                FirstMidName = "Student",
                EnrollmentDate = new DateTime(2020, 9, 1)
            };

            context.Students.Add(student);
            context.SaveChanges();

            var retrieved = context.Students.First();
            Assert.Equal("Test", retrieved.LastName);
            Assert.Equal("Student", retrieved.FirstMidName);
        }

        [Fact]
        public void SchoolContext_CanAddAndRetrieveCourse()
        {
            using var context = TestHelpers.CreateInMemoryContext();
            context.Departments.Add(new Department { DepartmentID = 1, Name = "Test Dept", Budget = 100, StartDate = DateTime.Now });
            context.SaveChanges();

